'use strict';

/**
 * Sliding window rate limiting middleware for Express.
 *
 * TRUE sliding window: for every request we keep the timestamps of recent
 * requests per client, drop any that fall outside `windowMs` from "now", and
 * decide based on how many remain. There is no fixed interval that resets the
 * whole bucket at once, so a client cannot double up by bursting on either
 * side of a fixed-window boundary.
 *
 * @param {Object}  [options]
 * @param {number}  [options.windowMs=60000]   Window size in milliseconds.
 * @param {number}  [options.maxRequests=100]  Max requests allowed per window.
 * @param {number}  [options.cleanupMs=60000]  How often the stale-entry sweep runs.
 * @param {(req) => string} [options.keyGenerator] Derive the client key (defaults to req.ip).
 * @returns {Function} Express middleware, augmented with a `.close()` method.
 */
function createRateLimiter(options = {}) {
  const {
    windowMs = 60000,
    maxRequests = 100,
    cleanupMs = 60000,
    keyGenerator = (req) => req.ip,
  } = options;

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (!Number.isInteger(maxRequests) || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive integer');
  }

  // Map<clientKey, number[]> -> ascending request timestamps in ms.
  const hits = new Map();

  /**
   * Drop timestamps older than the window. Timestamps are appended in
   * chronological order, so expired entries sit at the front; find the first
   * still-valid index and slice once.
   */
  function prune(timestamps, windowStart) {
    let firstValid = 0;
    while (firstValid < timestamps.length && timestamps[firstValid] <= windowStart) {
      firstValid++;
    }
    return firstValid === 0 ? timestamps : timestamps.slice(firstValid);
  }

  const middleware = function rateLimiter(req, res, next) {
    const now = Date.now();
    const windowStart = now - windowMs;
    const key = keyGenerator(req);

    // Pull, prune, keep only what's inside the sliding window.
    const recent = prune(hits.get(key) || [], windowStart);

    if (recent.length >= maxRequests) {
      // Over the limit. Capacity frees up when the OLDEST in-window request
      // exits the window, i.e. oldest + windowMs.
      const oldest = recent[0];
      const resetMs = oldest + windowMs;
      const retryAfter = Math.max(1, Math.ceil((resetMs - now) / 1000));

      // Persist the pruned list so memory doesn't grow while a client hammers us.
      hits.set(key, recent);

      res.setHeader('X-RateLimit-Limit', maxRequests);
      res.setHeader('X-RateLimit-Remaining', 0);
      res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));
      res.setHeader('Retry-After', retryAfter);

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter,
      });
      return; // Do NOT call next().
    }

    // Allowed: record this request.
    recent.push(now);
    hits.set(key, recent);

    const remaining = maxRequests - recent.length;
    // Reset = when the current oldest in-window request expires.
    const resetMs = recent[0] + windowMs;

    res.setHeader('X-RateLimit-Limit', maxRequests);
    res.setHeader('X-RateLimit-Remaining', remaining);
    res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));

    next();
  };

  // Periodic sweep: drop keys whose every timestamp has aged out of the window.
  // Bounds memory for clients that go quiet and never return.
  const cleanupTimer = setInterval(() => {
    const windowStart = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      const survivors = prune(timestamps, windowStart);
      if (survivors.length === 0) {
        hits.delete(key);
      } else if (survivors !== timestamps) {
        hits.set(key, survivors);
      }
    }
  }, cleanupMs);

  // Don't let the cleanup timer keep the Node process alive on its own.
  if (typeof cleanupTimer.unref === 'function') {
    cleanupTimer.unref();
  }

  // Fully stop the timer (graceful shutdown / tests).
  middleware.close = function close() {
    clearInterval(cleanupTimer);
    hits.clear();
  };

  return middleware;
}

module.exports = createRateLimiter;
module.exports.createRateLimiter = createRateLimiter;
```

