const express = require('express');
const createRateLimiter = require('./rateLimiter');

const app = express();

// IMPORTANT: req.ip behind a proxy/load balancer.
// Without this, req.ip is the address of the *nearest hop* (your proxy/CDN),
// so every client looks like the same IP and they share one bucket.
// Enable trust proxy so Express reads the client IP from X-Forwarded-For:
app.set('trust proxy', 1); // or true / a subnet / a hop count matching your infra.
// Only trust this header from proxies you actually control — clients can spoof
// X-Forwarded-For, so an over-permissive setting lets attackers forge IPs and
// dodge the limiter. If you have no proxy, leave trust proxy off (the default).

// 30 requests per 15 seconds, sliding.
const limiter = createRateLimiter({ windowMs: 15000, maxRequests: 30 });

app.use(limiter);

app.get('/', (req, res) => res.send('ok'));

const server = app.listen(3000);

// Graceful shutdown: stop the cleanup interval so the process can exit.
process.on('SIGTERM', () => {
  limiter.close();
  server.close();
});
```

### Notes on the algorithm
- **Sliding, not fixed:** the decision uses `now - windowMs` as the lower bound on every request, recomputed each time. Old timestamps continuously roll off the front rather than all clearing at a fixed tick.
- **`X-RateLimit-Reset`** points at when the *oldest in-window* request expires — the moment capacity first becomes available again — expressed in epoch seconds.
- **Memory:** the per-request prune keeps active buckets bounded, and the `setInterval` sweep evicts buckets for IPs that stopped sending traffic. `unref()` prevents the timer from holding the event loop open, and `close()` clears it explicitly.
- **Single-process only:** state lives in an in-memory `Map`. Across multiple workers/instances each process limits independently — use a shared store (e.g. Redis with sorted sets) if you need a global limit.

