'use strict';

/**
 * Sliding Window Rate Limiter Middleware for Express.js
 *
 * Uses a TRUE sliding window algorithm: each client's request timestamps are
 * stored and the window is evaluated relative to the *current* time on every
 * request — not relative to a fixed interval boundary.  This eliminates the
 * "double-burst" problem inherent in fixed-window implementations, where a
 * client can fire maxRequests just before a reset and maxRequests again
 * immediately after.
 *
 * ── Proxy note ───────────────────────────────────────────────────────────────
 * Express sets `req.ip` to the socket's remote address by default.  When your
 * app sits behind a reverse proxy (Nginx, load balancer, Cloudflare, etc.)
 * every request will appear to come from the proxy's IP, so ALL clients share
 * one rate-limit bucket — not what you want.
 *
 * Fix: set `app.set('trust proxy', 1)` (or the correct hop count) in your
 * Express app BEFORE attaching this middleware.  Express will then read the
 * leftmost IP from X-Forwarded-For and expose it as `req.ip`.
 *   https://expressjs.com/en/guide/behind-proxies.html
 * ─────────────────────────────────────────────────────────────────────────────
 *
 * @typedef {Object} RateLimiterOptions
 * @property {number} [windowMs=60000]   - Sliding window size in milliseconds.
 * @property {number} [maxRequests=100]  - Max requests allowed within windowMs.
 *
 * @typedef {Object} RateLimiter
 * @property {Function} middleware - Express middleware `(req, res, next) => void`.
 * @property {Function} close      - Clears the cleanup interval so the process
 *                                   can exit cleanly (call on graceful shutdown).
 */

/**
 * Creates a sliding-window rate limiter.
 *
 * @param {RateLimiterOptions} [options={}]
 * @returns {RateLimiter}
 */
function createRateLimiter(options = {}) {
  const windowMs    = options.windowMs    ?? 60_000; // default: 1 minute
  const maxRequests = options.maxRequests ?? 100;    // default: 100 req/window

  if (typeof windowMs !== 'number' || windowMs <= 0) {
    throw new TypeError('options.windowMs must be a positive number');
  }
  if (typeof maxRequests !== 'number' || maxRequests < 1) {
    throw new TypeError('options.maxRequests must be a positive integer');
  }

  /**
   * In-memory store: clientKey → sorted array of request timestamps (ms).
   *
   * Arrays stay sorted ascending because we always append to the end and
   * prune from the front — no sort() calls needed at any point.
   *
   * @type {Map<string, number[]>}
   */
  const store = new Map();

  // ── Background cleanup ─────────────────────────────────────────────────────
  // Runs every 60 s.  Drops map entries for IPs whose most-recent request is
  // older than windowMs — their window has fully expired, nothing to keep.
  const cleanupInterval = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [key, timestamps] of store) {
      // timestamps is ascending, so the last element is the most recent.
      if (timestamps.length === 0 || timestamps[timestamps.length - 1] < cutoff) {
        store.delete(key);
      }
    }
  }, 60_000);

  // unref() lets the Node.js event loop exit even while this timer is pending
  // (important for test suites and short-lived scripts).
  if (cleanupInterval.unref) {
    cleanupInterval.unref();
  }

  // ── Middleware ──────────────────────────────────────────────────────────────
  function middleware(req, res, next) {
    // req.ip honours the trust-proxy setting; fall back to the raw socket.
    const clientKey   = req.ip || req.socket?.remoteAddress || 'unknown';
    const now         = Date.now();
    const windowStart = now - windowMs;

    // Retrieve or initialise the client's timestamp list.
    let timestamps = store.get(clientKey);
    if (!timestamps) {
      timestamps = [];
      store.set(clientKey, timestamps);
    }

    // ── Slide the window ──────────────────────────────────────────────────────
    // Find the index of the first timestamp that is still inside the window.
    // Timestamps are ascending, so we can walk from the front — O(k) where k
    // is the number of expired entries (usually 0 or very few).
    let expiredCount = 0;
    while (expiredCount < timestamps.length && timestamps[expiredCount] <= windowStart) {
      expiredCount++;
    }
    if (expiredCount > 0) {
      timestamps.splice(0, expiredCount);
    }

    const currentCount = timestamps.length;

    // ── Reject: 429 Too Many Requests ─────────────────────────────────────────
    if (currentCount >= maxRequests) {
      // The oldest timestamp still in the window is the one that, once it
      // expires, will free the first slot for this client.
      const oldestTimestamp = timestamps[0];
      const retryAfterMs    = oldestTimestamp + windowMs - now;
      const retryAfterSec   = Math.ceil(retryAfterMs / 1000);

      res.set('Retry-After', String(retryAfterSec));
      return res.status(429).json({
        error:      'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
    }

    // ── Allow: record timestamp, set informational headers, continue ───────────
    timestamps.push(now); // maintain ascending order

    const remaining     = maxRequests - timestamps.length;

    // X-RateLimit-Reset: epoch second at which the *oldest* recorded request
    // exits the window, freeing the first slot.  Gives clients a precise
    // "earliest time to retry" rather than a full-window delay.
    const oldestInWindow = timestamps[0]; // always exists — we just pushed
    const resetEpochSec  = Math.ceil((oldestInWindow + windowMs) / 1000);

    res.set({
      'X-RateLimit-Limit':     String(maxRequests),
      'X-RateLimit-Remaining': String(remaining),
      'X-RateLimit-Reset':     String(resetEpochSec),
    });

    next();
  }

  // ── close() ────────────────────────────────────────────────────────────────
  /** Stop the background cleanup timer.  Call during graceful shutdown. */
  function close() {
    clearInterval(cleanupInterval);
  }

  return { middleware, close };
}

module.exports = { createRateLimiter };
