## Usage example — `app.js`

```js
const express = require('express');
const { createRateLimiter } = require('./middleware/rateLimiter');

const app = express();

// ── Trust proxy ──────────────────────────────────────────────────────────────
// Required when running behind Nginx / a load-balancer so that req.ip
// reflects the real client IP (from X-Forwarded-For) rather than the proxy.
// Set to the number of trusted proxy hops between the Internet and your app.
app.set('trust proxy', 1);

// ── Create rate limiter instances ────────────────────────────────────────────
// Global limiter: 100 requests per minute for every route.
const globalLimiter = createRateLimiter({ windowMs: 60_000, maxRequests: 100 });

// Stricter limiter for sensitive endpoints (e.g. auth): 10 req / 15 min.
const authLimiter = createRateLimiter({ windowMs: 15 * 60_000, maxRequests: 10 });

// ── Apply middleware ─────────────────────────────────────────────────────────
app.use(globalLimiter.middleware);                          // all routes

app.post('/login',    authLimiter.middleware, handleLogin); // auth routes only
app.post('/register', authLimiter.middleware, handleRegister);

// ── Route handlers ───────────────────────────────────────────────────────────
function handleLogin(req, res) {
  res.json({ message: 'logged in' });
}
function handleRegister(req, res) {
  res.json({ message: 'registered' });
}

// ── Server lifecycle ─────────────────────────────────────────────────────────
const server = app.listen(3000, () => console.log('Listening on :3000'));

// Graceful shutdown: stop cleanup timers so the process can exit cleanly.
function shutdown() {
  globalLimiter.close();
  authLimiter.close();
  server.close(() => process.exit(0));
}
process.on('SIGTERM', shutdown);
process.on('SIGINT',  shutdown);
```

